parameters.jsCode:
const raw = $json.choices[0].message.content;

const cleaned = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

const parsed = JSON.parse(cleaned);

return [{
  json: {
    category: parsed.category,
    confidence: Number(parsed.confidence),
    priority: parsed.priority
  }
}];

