parameters.jsCode:
const allItems = $input.all();

// Create an empty base object for our combined data
const combinedJson = {};
let combinedBinary = {};

// Loop through every incoming item and merge their properties together
for (const item of allItems) {
  if (item.json) {
    // Extract properties cleanly, handling strings or nested email objects
    const fromAddress = item.json.from?.value?.[0]?.address || item.json.from || "";

    // Assign values only if they are not empty/falsy
    if (fromAddress) combinedJson.from = fromAddress;
    if (item.json.subject) combinedJson.subject = item.json.subject;
    if (item.json.text || item.json.textPlain) {
      combinedJson.textPlain = item.json.text || item.json.textPlain;
    }
    if (item.json.category) combinedJson.category = item.json.category;
    if (item.json.confidence) combinedJson.confidence = item.json.confidence;
    if (item.json.priority) combinedJson.priority = item.json.priority;
  }

  // Keep binary data if present in any item
  if (item.binary) {
    combinedBinary = { ...combinedBinary, ...item.binary };
  }
}

// Fallback values for anything missing
return [{
  json: {
    from: combinedJson.from || "",
    subject: combinedJson.subject || "",
    textPlain: combinedJson.textPlain || "",
    category: combinedJson.category || "",
    confidence: combinedJson.confidence || 0,
    priority: combinedJson.priority || ""
  },
  binary: combinedBinary
}];

